import java.util.Scanner;
public class Main {
    static final long MOD = 1000000007;
    public static long powmod(long a, long b) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }
    public static long inv(long a) {
        return powmod(a, MOD - 2);
    }
    public static long comb(long n, long k) {
        long num = 1, den = 1;
        for (long i = 1; i <= k; i++) {
            num = (num * (n - i + 1)) % MOD;
            den = (den * i) % MOD;
        }
        return (num * inv(den)) % MOD;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long N = sc.nextLong(), K = sc.nextLong();
            long ans = 0;
            for (long i = 0; i <= K; i++) {
                long ways = comb(N - K + 1, i) * comb(N - i, K - i);
                ways %= MOD;
                ans = (ans + ways) % MOD;
            }
            System.out.println(ans);
        }
    }
}

